import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import api from "../api";
import Fuse from "fuse.js";

const BrowseEvents = () => {
  const [events, setEvents] = useState([]);
  const [filteredEvents, setFilteredEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [filters, setFilters] = useState({
    type: "all",
    eligibility: "all",
    startDate: "",
    endDate: "",
  });
  const [error, setError] = useState(null);

  // Fetch events
  useEffect(() => {
    const fetchEvents = async () => {
      try {
        setLoading(true);
        const token = localStorage.getItem("token");
        const res = await api.get("/events", {
          headers: { Authorization: `Bearer ${token}` },
        });
        setEvents(res.data);
      } catch (err) {
        console.error(err);
        setError("Failed to fetch events");
      } finally {
        setLoading(false);
      }
    };
    fetchEvents();
  }, []);

  // Apply search + filters locally
  useEffect(() => {
    let temp = [...events];

    if (filters.type !== "all") {
      temp = temp.filter((e) => e.type === filters.type);
    }
    if (filters.eligibility !== "all") {
      temp = temp.filter((e) => e.eligibility === filters.eligibility);
    }
    if (filters.startDate) {
      temp = temp.filter(
        (e) => new Date(e.startDate) >= new Date(filters.startDate)
      );
    }
    if (filters.endDate) {
      temp = temp.filter(
        (e) => new Date(e.endDate) <= new Date(filters.endDate)
      );
    }
    if (search) {
      const fuse = new Fuse(temp, {
        keys: ["name", "organiser.firstName", "organiser.lastName"],
        threshold: 0.3,
      });
      temp = fuse.search(search).map((r) => r.item);
    }
    setFilteredEvents(temp);
  }, [events, search, filters]);

  // Trending (Top 5 in last 24h)
  const trendingEvents = events
    .filter(
      (e) => new Date(e.createdAt) > new Date(Date.now() - 24 * 60 * 60 * 1000)
    )
    .sort((a, b) => b.participants.length - a.participants.length)
    .slice(0, 5);

  return (
    <div className="container mx-auto px-4 py-6">
      <h1 className="text-3xl font-bold mb-6 text-center">Browse Events</h1>

      {/* Search */}
      <div className="mb-4">
        <input
          type="text"
          placeholder="Search events or organisers..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full border border-gray-300 rounded px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-400"
        />
      </div>

      {/* Filters */}
      <div className="flex flex-wrap gap-4 mb-6">
        <select
          value={filters.type}
          onChange={(e) => setFilters({ ...filters, type: e.target.value })}
          className="border border-gray-300 rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-400"
        >
          <option value="all">All Types</option>
          <option value="normal">Normal</option>
          <option value="merchandise">Merchandise</option>
        </select>

        <select
          value={filters.eligibility}
          onChange={(e) =>
            setFilters({ ...filters, eligibility: e.target.value })
          }
          className="border border-gray-300 rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-400"
        >
          <option value="all">All Participants</option>
          <option value="IIIT Only">IIIT Only</option>
        </select>

        <input
          type="date"
          value={filters.startDate}
          onChange={(e) =>
            setFilters({ ...filters, startDate: e.target.value })
          }
          className="border border-gray-300 rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-400"
        />

        <input
          type="date"
          value={filters.endDate}
          onChange={(e) => setFilters({ ...filters, endDate: e.target.value })}
          className="border border-gray-300 rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-400"
        />
      </div>

      {loading && <p className="text-center">Loading events...</p>}
      {error && <p className="text-center text-red-500">{error}</p>}

      {/* Trending Events */}
      {trendingEvents.length > 0 && (
        <div className="mb-8">
          <h2 className="text-2xl font-semibold mb-3">Trending (24h)</h2>
          <div className="flex overflow-x-auto space-x-4 pb-2">
            {trendingEvents.map((e) => (
              <Link
                key={e._id}
                to={`/events/${e._id}`}
                className="min-w-[220px] border border-gray-200 rounded-lg p-4 hover:shadow-lg transition-shadow bg-white"
              >
                <h3 className="font-bold text-lg mb-1">{e.name}</h3>
                <p className="text-sm text-gray-600 mb-1">
                  Organizer: {e.organiser?.firstName} {e.organiser?.lastName}
                </p>
                <p className="text-sm text-gray-600">Type: {e.type}</p>
                <p className="text-sm text-gray-600">
                  Participants: {e.participants.length}
                </p>
              </Link>
            ))}
          </div>
        </div>
      )}

      {/* Filtered Events */}
      <div>
        <h2 className="text-2xl font-semibold mb-3">Filtered Events</h2>
        {filteredEvents.length === 0 ? (
          <p className="text-gray-500">No events found.</p>
        ) : (
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredEvents.map((e) => (
              <Link
                key={e._id}
                to={`/events/${e._id}`}
                className="border border-gray-200 rounded-lg p-5 hover:shadow-lg transition-shadow bg-white flex flex-col justify-between"
              >
                <div>
                  <h3 className="font-bold text-xl mb-2">{e.name}</h3>
                  <p className="text-gray-600 mb-1">
                    Organizer: {e.organiser?.firstName} {e.organiser?.lastName}
                  </p>
                  <p className="text-gray-600 mb-1">Type: {e.type}</p>
                  <p className="text-gray-600 mb-1">
                    Eligibility: {e.eligibility}
                  </p>
                  <p className="text-gray-600">
                    Dates: {new Date(e.startDate).toLocaleDateString()} -{" "}
                    {new Date(e.endDate).toLocaleDateString()}
                  </p>
                </div>
              </Link>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default BrowseEvents;
